form:Form.form:Scripts:
		///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function EnableControls()
{
}


var opts=null;

function ChangeTipo()
{                            
	var MyFILE=GetProxy().FileService().LoadFileXML("ALERT",Ctrl("d_tipo_alerta").GetXValue());
	Ctrl("d_alerta").SetXValue(MyFILE.GetAttr("label"));

	//Recorro los Grupos
	opts=new NomadXML("OPTS");
	var cnt=0;
	for(cur=MyFILE.FindElement("GROUPS").FirstChild(); cur; cur=cur.Next())
	{
		var opt=opts.AddTailElement("OPT");
		opt.SetAttr("value",cur.GetAttr("name"));
		opt.SetAttr("text" ,cur.GetAttr("label"));
		cnt++;
	}      

	//Cargo el Combo
	Ctrl("combo_mail_group").setOptions(createDoc(opts.ToString()));
	if (cnt==1) 
	{
		Ctrl("combo_mail_group").SetXValue(opts.FirstChild().GetAttr("value"));
		Ctrl("d_mail_group").SetXValue(opts.FirstChild().GetAttr("text"));
		Ctrl("c_mail_group").SetXValue(opts.FirstChild().GetAttr("value"));
	} else
	{
		Ctrl("combo_mail_group").SetXValue("");
		Ctrl("d_mail_group").SetXValue("");
		Ctrl("c_mail_group").SetXValue("");
	}
}                 

function ChangeMailGroup()
{         
	var opt=null;
	var valor=Ctrl("combo_mail_group").GetXValue();      

	//Busco la opcion selecionada  
  if (opts!=null)
  	opt=opts.FindElement2("OPT","value",valor);

	//Actualizo los Campos Ocultos                
	Ctrl("c_mail_group").SetXValue(opt==null?"":opt.GetAttr("value"));
	Ctrl("d_mail_group").SetXValue(opt==null?"":opt.GetAttr("text"));
}

function CustomOnLoad()
{                    
	OnLoad();

	//Concateno los text    
	if (Ctrl("WikiText"))
	{
		var WikiTXT="";
		WikiTXT+=Ctrl("o_text1").GetXValue();
		WikiTXT+=Ctrl("o_text2").GetXValue();
		WikiTXT+=Ctrl("o_text3").GetXValue();
		WikiTXT+=Ctrl("o_text4").GetXValue();
		Ctrl("WikiText").SetXValue(WikiTXT);	
	}
}
